valueString.value:
/*
@input: Client's age is less than 9 years
@pseudocode: Today's date − "Date of birth" < 9 years
@code: Client's age is less than 9 years-40
@decision: IMMZ.D2.DT.Dengue.3 doses with pre-vaccination screening: CYD-TDV (Dengvaxia), 3-dose schedule with pre-vaccination screening, the recommended strategy where feasible (pre-vaccination screening whereby only those tested seropositive would be vaccinated)
@decision: IMMZ.D2.DT.Dengue.3 doses without pre-vaccination screening: CYD-TDV (Dengvaxia), 3-dose schedule without pre-vaccination screening [when pre-vaccination screening is not feasible and in areas with recent documentation of seroprevalence rates of at least 80% by age 9 years]
*/
define "Client's age is less than 9 years":
  Encounter."Current Patient Age In Years" < 9

/*
@output: Client is not due for dengue vaccination Case 1
@pseudocode: "Immunization recommendation status" = "Not due"
*/
define "Client is not due for dengue vaccination Case 1":
  Encounter."Client's age is less than 9 years"

/*
@input: Client's age is more than 45 years
@pseudocode: Today's date − "Date of birth" > 45 years
@code: Client's age is more than 45 years-41
@decision: IMMZ.D2.DT.Dengue.3 doses with pre-vaccination screening: CYD-TDV (Dengvaxia), 3-dose schedule with pre-vaccination screening, the recommended strategy where feasible (pre-vaccination screening whereby only those tested seropositive would be vaccinated)
@decision: IMMZ.D2.DT.Dengue.3 doses without pre-vaccination screening: CYD-TDV (Dengvaxia), 3-dose schedule without pre-vaccination screening [when pre-vaccination screening is not feasible and in areas with recent documentation of seroprevalence rates of at least 80% by age 9 years]
*/
define "Client's age is more than 45 years":
  Encounter."Current Patient Age In Years" > 45

/*
@output: Client is not due for dengue vaccination Case 2
@pseudocode: "Immunization recommendation status" = "Not due"
*/
define "Client is not due for dengue vaccination Case 2":
  Encounter."Client's age is more than 45 years"

/*
@internal: Dengue serostatus Observation
*/
define "Dengue serostatus Observation":
  ([Observation: Concepts."Dengue serostatus"] O
    sort by end of effective.toInterval() desc).complete()

/*
@internal: Dengue serostatus Observation
*/
define "Dengue serostatus Observation":
  DengueElements."Dengue serostatus Observation".encounterOrOnBefore(EncounterId, Today)

/*
@input: Client's dengue serostatus is negative
@pseudocode: "Dengue serostatus" = "Negative"
@code: Client's dengue serostatus is negative-32
@decision: IMMZ.D2.DT.Dengue.3 doses with pre-vaccination screening: CYD-TDV (Dengvaxia), 3-dose schedule with pre-vaccination screening, the recommended strategy where feasible (pre-vaccination screening whereby only those tested seropositive would be vaccinated)
*/
define "Client's dengue serostatus is negative":
  First( "Dengue serostatus Observation" ).value ~ Concepts."Dengue-Negative"

/*
@output: Client is not due for dengue vaccination Case 3
@pseudocode: "Immunization recommendation status" = "Not due"
*/
define "Client is not due for dengue vaccination Case 3":
  Encounter."Client's dengue serostatus is negative"

/*
@internal: Dengue containing Doses Administered to Patient that are in the Primary series
*/
define "Dengue Primary Series Doses Administered to Patient":
  "Dengue Doses Administered to Patient".seriesPrimary()

/*
@internal: Number of Dengue Primary Series doses
*/
define "Number of Dengue Primary Series Doses Administered":
  Count("Dengue Primary Series Doses Administered to Patient")

/*
@input: One dengue primary series dose was administered
@pseudocode: Count of vaccines administered (where "Vaccine type" = "Dengue vaccines" and "Type of dose" = "Primary series") = 1
@code: One dengue primary series dose was administered-115
@decision: IMMZ.D2.DT.Dengue.3 doses with pre-vaccination screening: CYD-TDV (Dengvaxia), 3-dose schedule with pre-vaccination screening, the recommended strategy where feasible (pre-vaccination screening whereby only those tested seropositive would be vaccinated)
@decision: IMMZ.D2.DT.Dengue.3 doses without pre-vaccination screening: CYD-TDV (Dengvaxia), 3-dose schedule without pre-vaccination screening [when pre-vaccination screening is not feasible and in areas with recent documentation of seroprevalence rates of at least 80% by age 9 years]
*/
define "One dengue primary series dose was administered":
  "Number of Dengue Primary Series Doses Administered" = 1

/*
@input: Client's age is between 9 years and 45 years
@pseudocode: 9 years ≤ Today's date − "Date of birth" ≤ 45 years
@code: Client's age is between 9 years and 45 years-51
@decision: IMMZ.D2.DT.Dengue.3 doses with pre-vaccination screening: CYD-TDV (Dengvaxia), 3-dose schedule with pre-vaccination screening, the recommended strategy where feasible (pre-vaccination screening whereby only those tested seropositive would be vaccinated)
@decision: IMMZ.D2.DT.Dengue.3 doses without pre-vaccination screening: CYD-TDV (Dengvaxia), 3-dose schedule without pre-vaccination screening [when pre-vaccination screening is not feasible and in areas with recent documentation of seroprevalence rates of at least 80% by age 9 years]
*/
define "Client's age is between 9 years and 45 years":
  Encounter."Current Patient Age In Years" >= 9
  and Encounter."Current Patient Age In Years" <= 45

/*
@input: Client's dengue serostatus is positive
@pseudocode: "Dengue serostatus" = "Positive"
@code: Client's dengue serostatus is positive-32
@decision: IMMZ.D2.DT.Dengue.3 doses with pre-vaccination screening: CYD-TDV (Dengvaxia), 3-dose schedule with pre-vaccination screening, the recommended strategy where feasible (pre-vaccination screening whereby only those tested seropositive would be vaccinated)
*/
define "Client's dengue serostatus is positive":
  First( "Dengue serostatus Observation" ).value ~ Concepts."Dengue-Positive"

/*
@internal: Date of Latest Dengue Dose
*/
define "Date of Latest Dengue Dose":
  date from start of "Dengue Doses Administered to Patient".mostRecent().occurrence.toInterval()

/*
@input: The latest dengue dose was administered less than 6 months ago
@pseudocode: Today's date - Latest "Date and time of vaccination" (where "Vaccine type" = "Dengue vaccines") < 6 months
@code: The latest dengue dose was administered less than 6 months ago-106
@decision: IMMZ.D2.DT.Dengue.3 doses with pre-vaccination screening: CYD-TDV (Dengvaxia), 3-dose schedule with pre-vaccination screening, the recommended strategy where feasible (pre-vaccination screening whereby only those tested seropositive would be vaccinated)
@decision: IMMZ.D2.DT.Dengue.3 doses without pre-vaccination screening: CYD-TDV (Dengvaxia), 3-dose schedule without pre-vaccination screening [when pre-vaccination screening is not feasible and in areas with recent documentation of seroprevalence rates of at least 80% by age 9 years]
*/
define "The latest dengue dose was administered less than 6 months ago":
  "Date of Latest Dengue Dose" is not null
  and duration in months between "Date of Latest Dengue Dose" and Today < 6

/*
@output: Client is not due for dengue vaccination Case 4
@pseudocode: "Immunization recommendation status" = "Not due"
*/
define "Client is not due for dengue vaccination Case 4":
  Encounter."One dengue primary series dose was administered"
    and Encounter."Client's age is between 9 years and 45 years"
    and Encounter."Client's dengue serostatus is positive"
    and Encounter."The latest dengue dose was administered less than 6 months ago"

/*
@input: Two dengue primary series doses were administered
@pseudocode: Count of vaccines administered (where "Vaccine type" = "Dengue vaccines" and "Type of dose" = "Primary series") = 2
@code: Two dengue primary series doses were administered-115
@decision: IMMZ.D2.DT.Dengue.3 doses with pre-vaccination screening: CYD-TDV (Dengvaxia), 3-dose schedule with pre-vaccination screening, the recommended strategy where feasible (pre-vaccination screening whereby only those tested seropositive would be vaccinated)
@decision: IMMZ.D2.DT.Dengue.3 doses without pre-vaccination screening: CYD-TDV (Dengvaxia), 3-dose schedule without pre-vaccination screening [when pre-vaccination screening is not feasible and in areas with recent documentation of seroprevalence rates of at least 80% by age 9 years]
*/
define "Two dengue primary series doses were administered":
  "Number of Dengue Primary Series Doses Administered" = 2

/*
@output: Client is not due for dengue vaccination Case 5
@pseudocode: "Immunization recommendation status" = "Not due"
*/
define "Client is not due for dengue vaccination Case 5":
  Encounter."Two dengue primary series doses were administered"
    and Encounter."Client's age is between 9 years and 45 years"
    and Encounter."Client's dengue serostatus is positive"
    and Encounter."The latest dengue dose was administered less than 6 months ago"

/*
@output: Client is not due for dengue vaccination
@pseudocode: "Immunization recommendation status" = "Not due"
*/
define "Client is not due for dengue vaccination":
  "Client is not due for dengue vaccination Case 1"
    or "Client is not due for dengue vaccination Case 2"
    or "Client is not due for dengue vaccination Case 3"
    or "Client is not due for dengue vaccination Case 4"
    or "Client is not due for dengue vaccination Case 5"

/*
@input: No dengue primary series doses were administered
@pseudocode: Count of vaccines administered (where "Vaccine type" = "Dengue vaccines" and "Type of dose" = "Primary series") = 0
@code: No dengue primary series doses were administered-115
@decision: IMMZ.D2.DT.Dengue.3 doses with pre-vaccination screening: CYD-TDV (Dengvaxia), 3-dose schedule with pre-vaccination screening, the recommended strategy where feasible (pre-vaccination screening whereby only those tested seropositive would be vaccinated)
@decision: IMMZ.D2.DT.Dengue.3 doses without pre-vaccination screening: CYD-TDV (Dengvaxia), 3-dose schedule without pre-vaccination screening [when pre-vaccination screening is not feasible and in areas with recent documentation of seroprevalence rates of at least 80% by age 9 years]
*/
define "No dengue primary series doses were administered":
  "Number of Dengue Primary Series Doses Administered" = 0

/*
@output: Client is due for dengue vaccination Case 1
@pseudocode: "Immunization recommendation status" = "Due"
*/
define "Client is due for dengue vaccination Case 1":
  Encounter."No dengue primary series doses were administered"
    and Encounter."Client's age is between 9 years and 45 years"
    and Encounter."Client's dengue serostatus is positive"

/*
@input: The latest dengue dose was administered more than 6 months ago
@pseudocode: Today's date - Latest "Date and time of vaccination" (where "Vaccine type" = "Dengue vaccines") ≥ 6 months
@code: The latest dengue dose was administered more than 6 months ago-106
@decision: IMMZ.D2.DT.Dengue.3 doses with pre-vaccination screening: CYD-TDV (Dengvaxia), 3-dose schedule with pre-vaccination screening, the recommended strategy where feasible (pre-vaccination screening whereby only those tested seropositive would be vaccinated)
@decision: IMMZ.D2.DT.Dengue.3 doses without pre-vaccination screening: CYD-TDV (Dengvaxia), 3-dose schedule without pre-vaccination screening [when pre-vaccination screening is not feasible and in areas with recent documentation of seroprevalence rates of at least 80% by age 9 years]
*/
define "The latest dengue dose was administered more than 6 months ago":
  "Date of Latest Dengue Dose" is not null
  and duration in months between "Date of Latest Dengue Dose" and Today >= 6

/*
@output: Client is due for dengue vaccination Case 2
@pseudocode: "Immunization recommendation status" = "Due"
*/
define "Client is due for dengue vaccination Case 2":
  Encounter."One dengue primary series dose was administered"
    and Encounter."Client's age is between 9 years and 45 years"
    and Encounter."Client's dengue serostatus is positive"
    and Encounter."The latest dengue dose was administered more than 6 months ago"

/*
@output: Client is due for dengue vaccination Case 3
@pseudocode: "Immunization recommendation status" = "Due"
*/
define "Client is due for dengue vaccination Case 3":
  Encounter."Two dengue primary series doses were administered"
    and Encounter."Client's age is between 9 years and 45 years"
    and Encounter."Client's dengue serostatus is positive"
    and Encounter."The latest dengue dose was administered more than 6 months ago"

/*
@output: Client is due for dengue vaccination
@pseudocode: "Immunization recommendation status" = "Due"
*/
define "Client is due for dengue vaccination":
  "Client is due for dengue vaccination Case 1"
    or "Client is due for dengue vaccination Case 2"
    or "Client is due for dengue vaccination Case 3"

/*
@input: Three dengue primary series doses were administered
@pseudocode: Count of vaccines administered (where "Vaccine type" = "Dengue vaccines" and "Type of dose" = "Primary series") = 3
@code: Three dengue primary series doses were administered-115
@decision: IMMZ.D2.DT.Dengue.3 doses with pre-vaccination screening: CYD-TDV (Dengvaxia), 3-dose schedule with pre-vaccination screening, the recommended strategy where feasible (pre-vaccination screening whereby only those tested seropositive would be vaccinated)
@decision: IMMZ.D2.DT.Dengue.3 doses without pre-vaccination screening: CYD-TDV (Dengvaxia), 3-dose schedule without pre-vaccination screening [when pre-vaccination screening is not feasible and in areas with recent documentation of seroprevalence rates of at least 80% by age 9 years]
*/
define "Three dengue primary series doses were administered":
  "Number of Dengue Primary Series Doses Administered" = 3

/*
@output: Dengue immunization schedule is complete
@pseudocode: "Immunization recommendation status" = "Complete"
"Completed the primary vaccination series" = TRUE (where "Vaccine type" = "Dengue vaccines")"
*/
define "Dengue immunization schedule is complete":
  Encounter."Three dengue primary series doses were administered"
    and Encounter."Client's age is between 9 years and 45 years"

/*
@output: Dengue immunization schedule is complete Guidance
@guidance: Dengue immunization schedule is complete. Three dengue primary series doses were administered. 
Check for any other vaccines due.
*/
define "Dengue immunization schedule is complete Guidance":
  'Dengue immunization schedule is complete. Three dengue primary series doses were administered. 
Check for any other vaccines due.'

/*
@description: Returns true if the given reference is to the given resourceId
@comment: Returns true if the `resourceId` parameter exactly equals the tail of the given reference.
NOTE: This function assumes resources from the same source server.
*/
define fluent function references(reference FHIR.Reference, resourceId String):
  resourceId = Last(Split(reference.reference, '/'))

/* From FHIRCommon 4.1.0: */
/* @description: Normalizes a value that is a choice of timing-valued types to an equivalent interval @comment: Normalizes a choice type of FHIR.dateTime, FHIR.Period, FHIR.Timing, FHIR.instance, FHIR.string, FHIR.Age, or FHIR.Range types to an equivalent interval. This selection of choice types is a superset of the majority of choice types that are used as possible representations for timing-valued elements in FHIR, allowing this function to be used across any resource.
The input can be provided as a dateTime, Period, Timing, instant, string, Age, or Range. The intent of this function is to provide a clear and concise mechanism to treat single elements that have multiple possible representations as intervals so that logic doesn't have to account for the variability. More complex calculations (such as medication request period or dispense period calculation) need specific guidance and consideration. That guidance may make use of this function, but the focus of this function is on single element calculations where the semantics are unambiguous. If the input is a dateTime, the result a DateTime Interval beginning and ending on that dateTime. If the input is a Period, the result is a DateTime Interval. If the input is a Timing, an error is raised indicating a single interval cannot be computed from a Timing. If the input is an instant, the result is a DateTime Interval beginning and ending on that instant. If the input is a string, an error is raised indicating a single interval cannot be computed from a string. If the input is an Age, the result is a DateTime Interval beginning when the patient was the given Age, and ending immediately prior to when the patient was the given Age plus one year. If the input is a Range, the result is a DateTime Interval beginning when the patient was the Age given by the low end of the Range, and ending immediately prior to when the patient was the Age given by the high end of the Range plus one year.
NOTE: Due to the complexity of determining a single interval from a Timing or String type, this function will throw a run-time exception if it is used with a Timing or String. */ define fluent function toInterval(choice Choice<FHIR.dateTime, FHIR.Period, FHIR.Timing, FHIR.instant, FHIR.string, FHIR.Age, FHIR.Range>): case when choice is FHIR.dateTime then Interval[FHIRHelpers.ToDateTime(choice as FHIR.dateTime), FHIRHelpers.ToDateTime(choice as FHIR.dateTime)] when choice is FHIR.Period then FHIRHelpers.ToInterval(choice as FHIR.Period) when choice is FHIR.instant then Interval[FHIRHelpers.ToDateTime(choice as FHIR.instant), FHIRHelpers.ToDateTime(choice as FHIR.instant)] when choice is FHIR.Age then Interval[FHIRHelpers.ToDate(Patient.birthDate) + FHIRHelpers.ToQuantity(choice as FHIR.Age), FHIRHelpers.ToDate(Patient.birthDate) + FHIRHelpers.ToQuantity(choice as FHIR.Age) + 1 year) when choice is FHIR.Range then Interval[FHIRHelpers.ToDate(Patient.birthDate) + FHIRHelpers.ToQuantity((choice as FHIR.Range).low), FHIRHelpers.ToDate(Patient.birthDate) + FHIRHelpers.ToQuantity((choice as FHIR.Range).high) + 1 year) when choice is FHIR.Timing then Message(null as Interval<DateTime>, true, 'NOT_IMPLEMENTED', 'Error', 'Calculation of an interval from a Timing value is not supported') when choice is FHIR.string then Message(null as Interval<DateTime>, true, 'NOT_IMPLEMENTED', 'Error', 'Calculation of an interval from a String value is not supported') else null as Interval<DateTime> end
